17	/// Shared handle passed to the control listener and polled by tray/UI.
18	///
19	/// All fields are cheap to clone (Arc-wrapped).
20	#[derive(Clone)]
21	pub struct DaemonHandle {
22	    /// Macro dispatcher shared with the pipeline; used to push profile updates.
23	    pub dispatcher: Arc<Dispatcher>,
24	    /// Set true to suppress audio processing. The pipeline thread checks this
25	    /// on each frame and skips wake/VAD/STT while muted.
26	    pub muted: Arc<AtomicBool>,
27	    /// Name of the currently active profile, updated on every SwitchProfile.
28	    pub active_profile: Arc<RwLock<Option<String>>>,
29	    /// Set true while the wake-word listen window is open (written by coordinator).
30	    pub listening: Arc<AtomicBool>,
31	    /// Set true while PTT is held (written by coordinator).
32	    pub recording: Arc<AtomicBool>,
33	}
34	
35	impl DaemonHandle {
36	    /// Create a new handle wrapping the given dispatcher with all state flags initialised to false/None.
37	    pub fn new(dispatcher: Arc<Dispatcher>) -> Self {
38	        Self {
39	            dispatcher,
40	            muted: Arc::new(AtomicBool::new(false)),
41	            active_profile: Arc::new(RwLock::new(None)),
42	            listening: Arc::new(AtomicBool::new(false)),
43	            recording: Arc::new(AtomicBool::new(false)),
44	        }
45	    }
46	
47	    /// Derive the current [`DaemonState`] from the atomic flags, in priority order: Muted > Recording > Listening > Idle.
48	    pub fn state(&self) -> DaemonState {
49	        if self.muted.load(Ordering::Relaxed) {
50	            DaemonState::Muted
51	        } else if self.recording.load(Ordering::Relaxed) {
52	            DaemonState::Recording
53	        } else if self.listening.load(Ordering::Relaxed) {
54	            DaemonState::Listening
55	        } else {
56	            DaemonState::Idle
57	        }
58	    }
59	
60	    /// Build a full [`DaemonStatus`] snapshot (state + active profile + macro count) for Status queries.
61	    pub fn status(&self) -> DaemonStatus {
62	        let macro_count = self.dispatcher.macro_count();
63	        DaemonStatus {
64	            state: self.state(),
65	            active_profile: self.active_profile.read().unwrap().clone(),
66	            macro_count,
67	        }
68	    }
69	}
