71	/// Spawn the control channel listener on a Tokio task.
72	///
73	/// Listens on a Unix Domain Socket for commands from the CLI.
74	pub async fn spawn_control_listener(handle: DaemonHandle) -> Result<()> {
75	    let socket_path = get_socket_path()?;
76	
77	    // Clean up existing socket file if it exists
78	    if socket_path.exists() {
79	        std::fs::remove_file(&socket_path)
80	            .with_context(|| format!("Failed to remove existing socket: {}", socket_path.display()))?;
81	    }
82	
83	    let listener = UnixListener::bind(&socket_path)
84	        .with_context(|| format!("Failed to bind to UDS socket: {}", socket_path.display()))?;
85	
86	    // Set permissions to 0600 (user only)
87	    #[cfg(unix)]
88	    {
89	        use std::os::unix::fs::PermissionsExt;
90	        std::fs::set_permissions(&socket_path, std::fs::Permissions::from_mode(0o600))?;
91	    }
92	
93	    tracing::info!("Control channel listening on: {}", socket_path.display());
94	
95	    tokio::spawn(async move {
96	        loop {
97	            match listener.accept().await {
98	                Ok((mut stream, _)) => {
99	                    let h = handle.clone();
100	                    tokio::spawn(async move {
101	                        let (reader, mut writer) = stream.split();
102	                        let mut reader = BufReader::new(reader);
103	                        let mut line = String::new();
104	
105	                        if let Ok(n) = reader.read_line(&mut line).await {
106	                            if n == 0 { return; }
107	
108	                            let response = match serde_json::from_str::<ControlRequest>(&line) {
109	                                Ok(req) => {
110	                                    tracing::debug!("Control request: {:?}", req);
111	                                    match req {
112	                                        ControlRequest::Ping => ControlResponse::Pong,
113	                                        ControlRequest::Status => {
114	                                            ControlResponse::StatusData(h.status())
115	                                        }
116	                                        ControlRequest::Mute => {
117	                                            h.muted.store(true, Ordering::Relaxed);
118	                                            tracing::info!("Daemon muted via control socket");
119	                                            ControlResponse::Ok
120	                                        }
121	                                        ControlRequest::Unmute => {
122	                                            h.muted.store(false, Ordering::Relaxed);
123	                                            tracing::info!("Daemon unmuted via control socket");
124	                                            ControlResponse::Ok
125	                                        }
126	                                        ControlRequest::SwitchProfile { name } => {
127	                                            match tokio::task::block_in_place(|| {
128	                                                handle_switch_profile(&name, &h)
129	                                            }) {
130	                                                Ok(_) => ControlResponse::Ok,
131	                                                Err(e) => ControlResponse::Error { message: e.to_string() },
132	                                            }
133	                                        }
134	                                        ControlRequest::Shutdown => {
135	                                            // TODO: wire to CancellationToken in a future slice
136	                                            ControlResponse::Ok
137	                                        }
138	                                        _ => ControlResponse::Error { message: "Not yet implemented".into() },
139	                                    }
140	                                }
141	                                Err(e) => ControlResponse::Error { message: format!("Invalid JSON: {e}") },
142	                            };
143	
144	                            if let Ok(resp_json) = serde_json::to_string(&response) {
145	                                let _ = writer.write_all(resp_json.as_bytes()).await;
146	                                let _ = writer.write_all(b"\n").await;
147	                            }
148	                        }
149	                    });
150	                }
151	                Err(e) => {
152	                    tracing::error!("Control listener accept error: {e}");
153	                }
154	            }
155	        }
156	    });
157	
158	    Ok(())
159	}
160	
161	fn handle_switch_profile(name: &str, handle: &DaemonHandle) -> Result<()> {
162	    use crate::pack::Pack;
163	    use crate::pack::manager::ProfileManager;
164	
165	    let dir = crate::pack::get_profiles_dir()?.join(name);
166	    let pack = Pack::load_from_dir(&dir)?;
167	    handle.dispatcher.update_macros(pack.flatten());
168	
169	    // Track active profile for status queries
170	    *handle.active_profile.write().unwrap() = Some(name.to_string());
171	
172	    // Update persistence so it survives restart
173	    let mut manager = ProfileManager::load().unwrap_or(ProfileManager { active_profile: None });
174	    manager.active_profile = Some(name.to_string());
175	    manager.save()?;
176	
177	    Ok(())
178	}
