180	// Server-side path resolution: uses place_runtime_file, which creates the XDG runtime
181	// directory if it doesn't exist yet. The read-only counterpart lives in control/client.rs.
182	fn get_socket_path() -> Result<PathBuf> {
183	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
184	
185	    xdg.place_runtime_file("vibe-attack.sock")
186	        .context("Failed to place UDS socket in runtime directory")
187	}
