1	//! Pipeline coordinator: drain audio ringbuffer on an OS thread, run wake/VAD, queue STT jobs,
2	//! and emit stdout JSONL transcript events.
3	//!
4	//! Thread topology (locked):
5	//! - CPAL RT callback: push samples to ringbuf (no alloc/no block)
6	//! - Pipeline thread (OS): drain ringbuf; run wake + VAD segmentation; enqueue utterance jobs
7	//! - STT thread (OS): whisper-rs inference
8	//! - Output thread (OS): write JSONL to stdout (only stdout writer)
9	
10	use anyhow::{Context, Result};
11	use ringbuf::traits::Consumer;
12	use std::sync::{
13	    atomic::{AtomicBool, Ordering},
14	    Arc,
15	};
16	use std::time::{Duration, Instant};
17	use tokio_util::sync::CancellationToken;
18	
19	use ringbuf::HeapCons;
20	use crate::config::{Config, PipelineVerbosity};
21	use crate::pipeline::dispatcher::DispatchOutcome;
22	use crate::pipeline::jsonl::{JsonlVerbosity, JsonlWriter};
23	use crate::stt::{SttResult, SttService};
24	// Alias for readability: this module builds segmentation configs, not generic VAD configs.
25	use crate::vad::{VadConfig as SegCfg, VadSegmenter, FRAME_SAMPLES};
26	use crate::wake::WakeWord;
27	
28	/// Messages flowing from the dispatcher thread to the output thread.
29	enum OutputMsg {
30	    Utterance(SttResult),
31	    Dispatched { utterance_id: u64, macro_id: String, score: f32 },
32	    NoMatch { utterance_id: u64, transcript: String },
33	}
34	
35	/// Handles returned by [`spawn_pipeline`] so the caller can join threads on shutdown.
36	pub struct PipelineHandles {
37	    /// OS thread running the audio drain, VAD, and wake-word loop.
38	    pub pipeline: std::thread::JoinHandle<()>,
39	    /// OS thread that owns the stdout JSONL writer (sole writer to stdout).
40	    pub output: std::thread::JoinHandle<()>,
41	    /// STT service wrapper (holds the whisper-rs inference thread); `None` when STT is disabled.
42	    pub stt: Option<SttService>,
43	    /// Shared dispatcher handle — allows live macro registry updates via the control server.
44	    pub dispatcher: Arc<crate::pipeline::dispatcher::Dispatcher>,
45	}
46	
47	/// Spawn the pipeline worker threads and return handles to each.
48	///
49	/// ## Thread topology
50	///
51	/// ```text
52	/// CPAL RT callback ──► ringbuf (lock-free) ──► pipeline thread
53	///                                                    │
54	///                                             VAD segmenter (Silero)
55	///                                             wake-word detector
56	///                                                    │ UtteranceJob
57	///                                                    ▼
58	///                                              STT thread (whisper-rs)
59	///                                                    │ SttResult
60	///                                                    ▼
61	///                                           dispatcher thread (phrase match + macro inject)
62	///                                                    │ OutputMsg
63	///                                                    ▼
64	///                                            output thread (stdout JSONL, sole writer)
65	/// ```
66	///
67	/// All cross-thread queues are bounded `crossbeam_channel` channels; the VAD→STT queue
68	/// uses drop-oldest semantics under back-pressure to prevent unbounded audio buffering.
69	///
70	/// ## CPAL stream ownership
71	///
72	/// CRITICAL: do NOT pass the full `AudioHandle` here — callers must keep the
73	/// `StreamGuard` on the main thread (see `src/audio/mod.rs` for rationale).
74	/// Only the ringbuf `consumer` end should be forwarded into the worker.
75	pub fn spawn_pipeline(
76	    audio_consumer: HeapCons<f32>,
77	    config: Config,
78	    ptt_active: Arc<AtomicBool>,
79	    muted: Arc<AtomicBool>,
80	    macro_tx: std::sync::mpsc::Sender<crate::input::inject::MacroCmd>,
81	    shutdown: CancellationToken,
82	) -> Result<PipelineHandles> {
83	    let listen_window = Duration::from_secs(config.pipeline.listen_window_secs);
84	    // Wake pre-roll: keep a short rolling buffer of audio while idle so the first
85	    // post-wake command doesn't lose its leading syllables.
86	    //
87	    // NOTE: this is separate from VAD's own preroll (which only applies once
88	    // LISTENING is active). This buffer is used to "seed" the VAD segmenter at
89	    // the moment wake triggers.
90	    const WAKE_PREROLL_MS: u64 = 600;
91	    let wake_preroll_frames: usize = WAKE_PREROLL_MS.div_ceil(20) as usize;
92	
93	    // Build VAD config from config file.
94	    let ms_to_frames = |ms: u64| ms.div_ceil(20).max(1) as usize;
95	    let seg_cfg = SegCfg {
96	        start_threshold: config.vad.start_threshold,
97	        stop_threshold: config.vad.stop_threshold,
98	        min_speech_frames: ms_to_frames(config.vad.min_speech_ms),
99	        end_silence_frames: ms_to_frames(config.vad.end_silence_ms),
100	        preroll_frames: config.vad.preroll_ms.div_ceil(20) as usize,
101	        tail_frames: config.vad.tail_ms.div_ceil(20) as usize,
102	        max_utterance_frames: (config.vad.max_utterance_secs as usize) * 50, // 50 frames/sec
103	    };
104	
105	    // Wake mode wants “snappy” commands, not conservative segmentation.
106	    // Override a few knobs inside the wake LISTENING window to reduce end-of-speech
107	    // latency. Keep thresholds same as base VAD config.
108	    //
109	    // Targets:
110	    // - end_silence_ms smaller to cut earlier after last word
111	    // - min_speech_ms smaller to accept short commands
112	    // - tail/preroll smaller (wake pre-roll already handled separately)
113	    // - cap utterance length smaller for wake commands
114	    const WAKE_END_SILENCE_MS: u64 = 150;
115	    const WAKE_MIN_SPEECH_MS: u64 = 60;
116	    const WAKE_VAD_PREROLL_MS: u64 = 80;
117	    const WAKE_VAD_TAIL_MS: u64 = 80;
118	    const WAKE_MAX_UTTERANCE_SECS: usize = 4;
119	    const WAKE_FORCE_FLUSH_MS: u64 = 1200;
120	    let seg_cfg_wake = SegCfg {
121	        start_threshold: seg_cfg.start_threshold,
122	        // End speech sooner in noisy environments (wake commands are short).
123	        stop_threshold: (seg_cfg.start_threshold - 0.05).max(seg_cfg.stop_threshold),
124	        min_speech_frames: ms_to_frames(WAKE_MIN_SPEECH_MS),
125	        end_silence_frames: ms_to_frames(WAKE_END_SILENCE_MS),
126	        preroll_frames: ms_to_frames(WAKE_VAD_PREROLL_MS),
127	        tail_frames: ms_to_frames(WAKE_VAD_TAIL_MS),
128	        max_utterance_frames: WAKE_MAX_UTTERANCE_SECS * 50,
129	    };
130	
131	    // Output thread owns stdout writer and ensures stdout remains JSONL-only.
132	    let (out_tx, out_rx) = crossbeam_channel::bounded::<OutputMsg>(16);
133	
134	    // Dispatcher thread receives STT results, runs macros, then forwards to JSONL output
135	    let (dispatch_tx, dispatch_rx) = crossbeam_channel::bounded::<SttResult>(8);
136	    let dispatch_rx_for_drop = dispatch_rx.clone();
137	
138	    let dispatcher = Arc::new(crate::pipeline::dispatcher::Dispatcher::new(
139	        config.stt.confidence_threshold,
140	        config.macros.clone(),
141	        macro_tx,
142	        config.timing.dwell_ms,
143	        config.timing.gap_ms,
144	    ));
145	    let dispatcher_for_thread = Arc::clone(&dispatcher);
146	    let dispatcher_shutdown = shutdown.clone();
147	    let dispatch_out_tx = out_tx.clone();
148	    std::thread::spawn(move || {
149	        tracing::info!("Dispatcher thread started");
150	        while !dispatcher_shutdown.is_cancelled() {
151	            match dispatch_rx.recv_timeout(Duration::from_millis(50)) {
152	                Ok(r) => {
153	                    let utterance_id = r.utterance_id;
154	                    let transcript = r.text.clone();
155	                    match dispatcher_for_thread.process(&r.text) {
156	                        DispatchOutcome::Fired { macro_id, score } => {
157	                            let _ = dispatch_out_tx.send(OutputMsg::Dispatched { utterance_id, macro_id, score });
158	                        }
159	                        DispatchOutcome::NoMatch => {
160	                            let _ = dispatch_out_tx.send(OutputMsg::NoMatch { utterance_id, transcript });
161	                        }
162	                    }
163	                    let _ = dispatch_out_tx.send(OutputMsg::Utterance(r));
164	                }
165	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
166	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
167	            }
168	        }
169	        tracing::info!("Dispatcher thread stopped");
170	    });
171	
172	    let jsonl_verbosity = match config.pipeline.verbosity {
173	        PipelineVerbosity::Summary => JsonlVerbosity::SummaryOnly,
174	        PipelineVerbosity::Stages => JsonlVerbosity::Stages,
175	    };
176	
177	    let output_shutdown = shutdown.clone();
178	    let output = std::thread::spawn(move || {
179	        let stdout = std::io::stdout();
180	        let mut w = JsonlWriter::new(stdout.lock(), jsonl_verbosity);
181	
182	        // Emit a startup event to force a flush and verify stdout is working (D-19).
183	        if let Err(e) = w.write_event(&crate::pipeline::jsonl::JsonlEvent::Status {
184	            message: "pipeline_started",
185	            mono_ms: 0,
186	        }) {
187	            tracing::error!("Failed to write startup JSONL: {e}");
188	        }
189	
190	        while !output_shutdown.is_cancelled() {
191	            match out_rx.recv_timeout(Duration::from_millis(50)) {
192	                Ok(OutputMsg::Utterance(mut r)) => {
193	                    r.timings.mark_output_done();
194	                    if let Err(e) = w.write_utterance(
195	                        r.utterance_id,
196	                        &r.text,
197	                        r.audio_ms,
198	                        r.stt_ms,
199	                        r.timings,
200	                        r.start_frame_idx,
201	                        r.end_frame_idx,
202	                    ) {
203	                        tracing::error!("Failed to write stdout JSONL: {e}");
204	                    }
205	                }
206	                Ok(OutputMsg::Dispatched { utterance_id, macro_id, score }) => {
207	                    if let Err(e) = w.write_dispatch(utterance_id, &macro_id, score) {
208	                        tracing::error!("Failed to write dispatch JSONL: {e}");
209	                    }
210	                }
211	                Ok(OutputMsg::NoMatch { utterance_id, transcript }) => {
212	                    if let Err(e) = w.write_no_match(utterance_id, &transcript) {
213	                        tracing::error!("Failed to write no_match JSONL: {e}");
214	                    }
215	                }
216	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
217	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
218	            }
219	        }
220	    });
221	
222	    // STT service (optional, feature-gated) is created before threads (fail-fast).
223	    let stt: Option<SttService> = if config.stt.enabled {
224	        let model_path = config
225	            .stt
226	            .model_path
227	            .as_ref()
228	            .context("stt.enabled but stt.model_path is not set")?;
229	
230	        #[cfg(not(feature = "stt"))]
231	        {
232	            let _ = model_path;
233	            return Err(anyhow::anyhow!(
234	                "Config enables STT, but this build was compiled without `--features stt`."
235	            ));
236	        }
237	
238	        #[cfg(feature = "stt")]
239	        {
240	            Some(
241	                SttService::new(model_path, config.stt.initial_prompt.clone(), shutdown.clone())
242	                    .context("create STT service")?
243	                    .spawn()
244	                    .context("spawn STT thread")?,
245	            )
246	        }
247	    } else {
248	        None
249	    };
250	
251	    let stt_submit = stt.as_ref().map(|s| s.submitter());
252	    let stt_results = stt.as_ref().map(|s| s.result_receiver());
253	
254	    // Wake word (optional). Construct before pipeline loop (fail-fast).
255	    let wake = if config.wake.enabled {
256	        Some(WakeWord::new(&config.wake).context("init wake word")?)
257	    } else {
258	        None
259	    };
260	
261	    // ORT_DYLIB_PATH auto-discovery: point the `ort` crate at the same
262	    // libonnxruntime.so that sherpa-onnx ships (shared feature), so both
263	    // runtimes share one ORT global environment instead of colliding.
264	    // Respect any existing user-supplied value.
265	    if std::env::var_os("ORT_DYLIB_PATH").is_none() {
266	        if let Ok(exe) = std::env::current_exe() {
267	            if let Some(exe_dir) = exe.parent() {
268	                let so_path = exe_dir.join("libonnxruntime.so");
269	                // SAFETY: single-threaded at this point — no pipeline threads spawned yet.
270	                unsafe { std::env::set_var("ORT_DYLIB_PATH", &so_path) };
271	                tracing::info!(path = %so_path.display(), "ORT_DYLIB_PATH auto-set to sherpa-onnx shared library");
272	            }
273	        }
274	    }
275	
276	    // VAD model is required for utterance segmentation (CPU-only baseline, D-16).
277	    //
278	    // IMPORTANT: `ort` (ONNX Runtime) can panic at runtime if `libonnxruntime.so`
279	    // is not discoverable. Convert that into a normal, actionable startup error
280	    // instead of crashing the process.
281	    let start_vad = std::time::Instant::now();
282	    let mut silero = std::panic::catch_unwind(|| {
283	        silero_vad_rust::silero_vad::model::load_silero_vad_with_options(
284	            silero_vad_rust::silero_vad::model::LoadOptions {
285	                force_onnx_cpu: true,
286	                ..Default::default()
287	            },
288	        )
289	    })
290	    .map_err(|_| {
291	        anyhow::anyhow!(
292	            "Failed to load Silero VAD: ONNX Runtime could not be loaded.\n\
293	             Fix: install ONNX Runtime so `libonnxruntime.so` is in your library path, or set ORT_DYLIB_PATH to the full path of `libonnxruntime.so`.\n\
294	             Example (Arch/CachyOS): `sudo pacman -S onnxruntime`"
295	        )
296	    })?
297	    .context("load silero VAD model")?;
298	    tracing::info!("Silero VAD loaded in {}ms", start_vad.elapsed().as_millis());
299	
300	    // NOTE: the CPAL stream guard is intentionally NOT in this function — the
301	    // caller (main) keeps it alive. We only own the ringbuf consumer end.
302	    let pipeline_shutdown = shutdown.clone();
303	
304	    let pipeline = std::thread::spawn(move || {
305	        tracing::info!("Pipeline thread started");
306	
307	        let mut seg = VadSegmenter::new(seg_cfg.clone());
308	        let mut consumer = audio_consumer;
309	
310	        let mut pending = Vec::<f32>::with_capacity(FRAME_SAMPLES * 8);
311	        let mut pending_idx: usize = 0;
312	        let mut tmp = [0.0f32; 1024];
313	        let mut frame = [0.0f32; FRAME_SAMPLES];
314	
315	        let mut listening_until: Option<Instant> = None;
316	        let mut listening_started_at: Option<Instant> = None;
317	        let mut prev_ptt = false;
318	
319	        // Rolling wake pre-roll ring: N frames of 20ms each.
320	        let mut wake_preroll: Vec<[f32; FRAME_SAMPLES]> =
321	            vec![[0.0; FRAME_SAMPLES]; wake_preroll_frames.max(1)];
322	        let mut wake_preroll_pos: usize = 0; // next write index
323	        let mut wake_preroll_len: usize = 0; // valid frames in ring (<= capacity)
324	
325	        // Heartbeat: log samples/frames received every 5s to confirm audio is flowing.
326	        let mut heartbeat_samples: usize = 0;
327	        let mut heartbeat_last = Instant::now();
328	
329	        // PTT-mode direct capture: all audio while PTT is held lands here.
330	        // On release the entire buffer is sent to STT unconditionally, bypassing
331	        // the VAD speech-gate. VAD is still used for the wake-word listen window.
332	        let mut ptt_audio: Vec<f32> = Vec::with_capacity(FRAME_SAMPLES * 200); // ~4 sec
333	        let mut ptt_utterance_id: u64 = 0;
334	        let mut ptt_next_id: u64 = 1; // monotonic ID counter for PTT utterances
335	        let mut ptt_timings = crate::pipeline::timing::UtteranceTimings::new();
336	        let mut ptt_start_frame: u64 = 0;
337	        let mut ptt_frame_count: u64 = 0;
338	
339	        while !pipeline_shutdown.is_cancelled() {
340	            // Always drain completed STT results first so they are never lost regardless
341	            // of PTT state.  Previously this was inside the VAD branch and was skipped by
342	            // `continue` while PTT was idle, causing results to accumulate forever.
343	            if let Some(stt_results) = &stt_results {
344	                while let Ok(r) = stt_results.try_recv() {
345	                    if crate::vad::try_send_drop_oldest(&dispatch_tx, &dispatch_rx_for_drop, r).is_err() {
346	                        break;
347	                    }
348	                }
349	            }
350	
351	            // Drain some samples from ringbuf.
352	            let n = consumer.pop_slice(&mut tmp);
353	            if n == 0 {
354	                std::thread::sleep(Duration::from_millis(5));
355	            } else {
356	                pending.extend_from_slice(&tmp[..n]);
357	                heartbeat_samples += n;
358	            }
359	
360	            // Periodic heartbeat so we can confirm audio is flowing (or diagnose silence).
361	            if heartbeat_last.elapsed() >= Duration::from_secs(5) {
362	                tracing::debug!(samples = heartbeat_samples, "pipeline heartbeat: audio samples received in last 5s");
363	                heartbeat_samples = 0;
364	                heartbeat_last = Instant::now();
365	            }
366	
367	            // Compact pending buffer occasionally.
368	            if pending_idx > FRAME_SAMPLES * 16 {
369	                pending.drain(0..pending_idx);
370	                pending_idx = 0;
371	            }
372	
373	            while pending.len().saturating_sub(pending_idx) >= FRAME_SAMPLES {
374	                frame.copy_from_slice(&pending[pending_idx..pending_idx + FRAME_SAMPLES]);
375	                pending_idx += FRAME_SAMPLES;
376	
377	                let now = Instant::now();
378	                let ptt = ptt_active.load(Ordering::Relaxed);
379	                let listening = listening_until.map(|t| now < t).unwrap_or(false);
380	
381	                // Mute gate: drop frame and reset any in-progress state.
382	                if muted.load(Ordering::Relaxed) {
383	                    if prev_ptt { prev_ptt = false; }
384	                    if listening_until.is_some() {
385	                        listening_until = None;
386	                        listening_started_at = None;
387	                        wake_preroll_len = 0;
388	                        seg = VadSegmenter::new(seg_cfg.clone());
389	                    }
390	                    continue;
391	                }
392	
393	                // PTT pressed: start or continue recording directly into ptt_audio.
394	                if ptt {
395	                    if !prev_ptt {
396	                        // Rising edge: begin new PTT utterance.
397	                        ptt_audio.clear();
398	                        ptt_utterance_id = ptt_next_id;
399	                        ptt_next_id += 1;
400	                        ptt_timings = crate::pipeline::timing::UtteranceTimings::new();
401	                        ptt_start_frame = ptt_frame_count;
402	                        tracing::debug!(utterance_id = ptt_utterance_id, "PTT utterance started");
403	                    }
404	                    ptt_audio.extend_from_slice(&frame);
405	                    ptt_frame_count += 1;
406	                    prev_ptt = true;
407	                    continue;
408	                }
409	
410	                // PTT just released: send entire PTT buffer to STT.
411	                if prev_ptt {
412	                    let audio_len = ptt_audio.len();
413	                    let min_samples = (crate::vad::SAMPLE_RATE_HZ as usize) / 10; // 100 ms minimum
414	                    tracing::debug!(
415	                        utterance_id = ptt_utterance_id,
416	                        samples = audio_len,
417	                        "PTT released – submitting to STT"
418	                    );
419	                    if audio_len >= min_samples {
420	                        // For PTT captures we bypass VAD, but we still want a stable
421	                        // monotonic milestone so latency fields are meaningful.
422	                        ptt_timings.mark_vad_done();
423	                        let job = crate::vad::UtteranceJob {
424	                            utterance_id: ptt_utterance_id,
425	                            audio: std::mem::take(&mut ptt_audio),
426	                            timings: ptt_timings,
427	                            start_frame_idx: ptt_start_frame,
428	                            end_frame_idx: ptt_frame_count,
429	                        };
430	                        if let Some(stt_submit) = &stt_submit {
431	                            if let Err(e) = stt_submit.try_submit(job) {
432	                                tracing::warn!(utterance_id = ptt_utterance_id, "STT submit failed: {e}");
433	                            }
434	                        }
435	                    } else {
436	                        tracing::debug!(utterance_id = ptt_utterance_id, samples = audio_len, "PTT too short, skipping STT");
437	                        ptt_audio.clear();
438	                    }
439	                    // Reset the VAD segmenter so stale state doesn't bleed into
440	                    // the next wake-word listen window.
441	                    seg = VadSegmenter::new(seg_cfg.clone());
442	                }
443	                prev_ptt = false;
444	
445	                // Wake-word detection while idle (no PTT) to enter LISTENING (D-17/D-18).
446	                if !ptt && !listening {
447	                    if let Some(w) = &wake {
448	                        // Maintain rolling pre-roll while idle so we can seed VAD
449	                        // immediately when wake triggers.
450	                        wake_preroll[wake_preroll_pos] = frame;
451	                        wake_preroll_pos = (wake_preroll_pos + 1) % wake_preroll.len();
452	                        wake_preroll_len = wake_preroll_len.saturating_add(1).min(wake_preroll.len());
453	
454	                        w.accept_audio(16_000, &frame);
455	                        w.decode_until_not_ready();
456	                        if let Some(keyword) = w.take_keyword() {
457	                            tracing::info!(keyword = %keyword, "Wake word triggered; entering LISTENING window");
458	                            listening_until = Some(now + listen_window);
459	                            listening_started_at = Some(now);
460	                            w.reset();
461	                            // Seed VAD with pre-roll frames captured while idle.
462	                            // This helps include the first command word if it started
463	                            // right before the wake trigger fired.
464	                            seg = VadSegmenter::new(seg_cfg_wake.clone());
465	                            if wake_preroll_len > 0 {
466	                                let cap = wake_preroll.len();
467	                                let start = (wake_preroll_pos + cap - wake_preroll_len) % cap;
468	                                for i in 0..wake_preroll_len {
469	                                    let idx = (start + i) % cap;
470	                                    let _ = seg.push_frame_silero(&mut silero, &wake_preroll[idx]);
471	                                }
472	                            }
473	                            // Also feed current frame into VAD below (do not `continue`).
474	                        } else {
475	                            continue;
476	                        }
477	                    } else {
478	                        continue;
479	                    }
480	                }
481	
482	                // Wake-word listen window: run VAD segmentation.
483	                match seg.push_frame_silero(&mut silero, &frame) {
484	                    Ok(Some(mut job)) => {
485	                        job.timings.mark_vad_done();
486	
487	                        if let Some(stt_submit) = &stt_submit {
488	                            if let Err(e) = stt_submit.try_submit(job) {
489	                                tracing::warn!("STT submit failed: {e}");
490	                            }
491	                        }
492	                    }
493	                    Ok(None) => {}
494	                    Err(e) => tracing::warn!("VAD error: {e}"),
495	                }
496	
497	                // Wake mode fallback: if VAD never observes "enough silence" due to
498	                // noise/AGC, force-flush after a short budget once LISTENING started.
499	                if listening {
500	                    if let Some(t0) = listening_started_at {
501	                        if t0.elapsed() >= Duration::from_millis(WAKE_FORCE_FLUSH_MS) {
502	                            if let Some(mut job) = seg.force_flush() {
503	                                tracing::debug!(
504	                                    utterance_id = job.utterance_id,
505	                                    "Wake force-flush after {}ms",
506	                                    WAKE_FORCE_FLUSH_MS
507	                                );
508	                                job.timings.mark_vad_done();
509	                                if let Some(stt_submit) = &stt_submit {
510	                                    if let Err(e) = stt_submit.try_submit(job) {
511	                                        tracing::warn!("STT submit failed: {e}");
512	                                    }
513	                                }
514	                            }
515	                            // Reset timer so we don't spam force_flush.
516	                            listening_started_at = Some(now);
517	                        }
518	                    }
519	                }
520	
521	                // If LISTENING window expired, reset wake pre-roll so next command
522	                // doesn't get polluted by prior-window audio.
523	                if listening_until.map(|t| now >= t).unwrap_or(false) {
524	                    listening_until = None;
525	                    listening_started_at = None;
526	                    wake_preroll_len = 0;
527	                    seg = VadSegmenter::new(seg_cfg.clone());
528	                }
529	            }
530	        }
531	
532	        tracing::info!("Pipeline thread stopped");
533	    });
534	
535	    Ok(PipelineHandles { pipeline, output, stt, dispatcher })
536	}
